-- CNB Primaria - Comunicación y Lenguaje L 1 - Segundo Grado
-- Fuente: https://cnbguatemala.org/wiki/Dosificaci%C3%B3n_de_los_aprendizajes_-_%C3%81rea_de_Comunicaci%C3%B3n_y_Lenguaje_L_1_-_Segundo_Grado

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Grado', 'Comunicación y Lenguaje L 1', '1. Escucha diferentes mensajes demostrando comprensión por medio de gestos, movimientos corporales o en forma oral. 1.1. Demuestra respeto hacia las personas a quienes escucha y hacia las prácticas comunicativas de otras culturas. 1.2. Utiliza gestos y lenguaje corporal para responder a mensajes escuchados. 1.3. Establece la relación entre símbolo, sonido y significado (Conciencia fonológica). 1.4. Emite opiniones que reflejan diferentes niveles de comprensión de lo escuchado.', ARRAY['1.1.1. Demostración de respeto hacia la persona que habla (posición del cuerpo, gestos faciales, silencio cuando otras y otros están en el uso de la palabra).', '1.1.2. Práctica de normas de cortesía en conversaciones, diálogos y discusiones.', '1.1.3. Demostración de respeto hacia gestos y prácticas comunicativas comunes en otros idiomas y culturas del país.', '1.1.4. Uso de expresiones de cortesía: saludo, despedida, excusas, agradecimientos, disculpas al interrumpir.', '1.1.5. Demostración de respeto por el derecho a la diferencia de opinión.', '1.2.1. Seguimiento de instrucciones orales con tres o más eventos.', '1.2.2. Interpretación de rimas, cuentos, poemas, canciones, entre otros, por medio de gestos y movimientos corporales.', '1.2.3. Reproducción de lo escuchado por medios electrónicos: radio, cintas, discos compactos, entre otros.', '1.3.1. Aplicación de destrezas de comunicación oral: entonación, fluidez, volumen.', '1.3.2. Reconocimiento de palabras específicas que escucha en párrafos descriptivos o narrativos y poemas.', '1.3.3. Identificación del fonema inicial y final en palabras que escucha.', '1.3.4. Reconocimiento de la rima en el lenguaje poético.', '1.3.5. Identificación de ritmo, rima y sonoridad en el lenguaje poético.', '1.3.6. Identificación de la diferencia que representa, en cuanto a sonido y significado, la sustitución de una letra en palabras determinadas.', '1.3.7. Reproducción oral del ritmo, la rima y la sonoridad en elementos expresados en lenguaje poético.', '1.3.8. Segmentación de las sílabas que conforman palabras que escucha según los fonemas que las integran.', '1.3.9. Identificación de las sílabas que integran determinadas palabras que escucha.', '1.4.1. Repetición de información explícita expresada oralmente por medio de diálogos, lecturas o narraciones que escucha (Comprensión literal).', '1.4.2. Establecimiento de similitudes y diferencias entre las características de los personajes que protagonizan los cuentos o las narraciones que se escuchan.', '1.4.3. Asociación de situaciones en las narraciones que escucha con la experiencia personal.', '1.4.4. Enumeración, explicación y justificación de los contenidos de los mensajes o presentaciones que escucha.', '1.4.5. Anticipación o predicción de lo que pueda ocurrir en los mensajes que escucha (Comprensión semántica).', '1.4.6. Inferencia o suposición de ideas relacionadas con los mensajes que escucha (Comprensión semántica).', '1.4.7. Expresión de opiniones que reflejen análisis y evaluación con respecto al texto que se lee o escucha (Comprensión crítica).']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '2. Expresa oralmente, su respuesta a mensajes emitidos por otras personas. 2.1. Utiliza estrategias del lenguaje oral que le permiten obtener información precisa. 2.2. Utiliza diferentes estrategias para responder oralmente los mensajes recibidos. 2.3. Demuestra seguridad al emitir, oralmente, sus opiniones ante mensajes recibidos.', ARRAY['2.1.1. Solicitud de información o explicaciones dentro del aula.', '2.1.2. Formulación de respuestas según información solicitada.', '2.1.3. Inicio y desarrollo de conversaciones y diálogos de tipo social y personal dentro del aula y del ambiente escolar.', '2.2.1. Emisión de información que se solicita.', '2.2.2. Reproducción oral de lo escuchado, recitándolo o parafraseándolo.', '2.2.3. Emisión de opiniones personales dentro y fuera del aula.', '2.2.4. Utilización de argumentos pertinentes para fundamentar una idea u opinión.', '2.2.5. Narración de experiencias propias o de otros y de mensajes orales que se escuchan resumiendo o aclarando la información.', '2.2.6. Narración de cuentos, leyendas, poemas y otros tipos de texto que escucha.', '2.2.7. Reproducción de juegos verbales: dichos populares, refranes.', '2.3.1. Organización lógica y secuencial de la información.', '2.3.2. Descripción o narración de experiencias utilizando oraciones completas y pronunciando claramente las palabras.', '2.3.3. Descripción de personajes, lugares u objetos utilizando los adjetivos apropiados.']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '3. Utiliza el lenguaje no verbal como un auxiliar de la comunicación oral en la manifestación de sus ideas, sentimientos y emociones. 3.1. Utiliza gestos faciales y movimientos corporales como apoyo en su comunicación oral. 3.2. Utiliza sonidos onomatopéyicos para reforzar sus mensajes orales. 3.3. Utiliza la información presentada por medio de signos, símbolos y otros recursos gráficos.', ARRAY['3.1.1. Utilización de los elementos del lenguaje no verbal (gestos, mímica, movimientos corporales, desplazamientos, voces onomatopéyicas) como apoyo en la manifestación de sus ideas.', '3.1.2. Utilización de gestos y movimientos corporales en la comunicación de estados de ánimo.', '3.1.3. Descripción de características de objetos y de personas por medio de gestos y movimientos corporales.', '3.1.4. Descripción oral de la relación entre direccionalidad y movimientos corporales que indican la dirección de su desplazamiento en el espacio.', '3.1.5. Utilización de gestos y movimientos corporales para indicar la posición de objetos en el espacio y la relación entre ellos.', '3.1.6. Participación voluntaria en dramatizaciones formales o informales, espontáneas o dirigidas.', '3.1.7. Identificación de los elementos básicos de la dramatización (tema, ambiente, personajes, entre otros).', '3.1.8. Representación de cuentos por medio del lenguaje corporal, de la danza y del teatro.', '3.1.9. Representación de juegos e historias mediante el lenguaje corporal.', '3.1.10. Utilización de la poesía coral como medio de expresión.', '3.2.1. Utilización de palabras que imitan el sonido de aquello que describen.', '3.2.2. Utilización de palabras que reproducen el sonido de animales.', '3.2.3. Utilización de palabras que imitan el sonido producido por instrumentos musicales.', '3.2.4. Identificación de palabras que nombran el efecto que produce el sonido emitido por animales.', '3.3.1. Diferenciación entre signos, señales convencionales y señales naturales frecuentemente utilizados en su entorno.', '3.3.2. Respeto por las señales viales en la escuela y la comunidad.', '3.3.3. Interpretación de la información presentada por medio de tablas y otros recursos gráficos.', '3.3.4. Utilización de símbolos, señales y otros recursos gráficos para establecer comunicación con otros.']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '4. Utiliza estrategias de lectura con propósitos informativos y recreativos. 4.1. Interpreta el significado de ilustraciones, imágenes, signos, símbolos y señales del entorno y las relaciona con textos escritos. 4.2. Demuestra fluidez en su lectura oral. 4.3. Demuestra fluidez en lectura silenciosa. 4.4. Identifica palabras con diferentes significados demostrando comprensión de los conceptos que representan. 4.5. Identifica los hechos y detalles o elementos importantes en lo que lee y sus implicaciones para anticipar los eventos en un texto determinado. 4.6. Emite opinión con respecto al contenido de los textos que lee y analiza. 4.7. Lee para obtener información.', ARRAY['4.1.1. Asociación de ilustraciones con textos que las describen.', '4.1.2. Identificación de palabras en negrilla, palabras subrayadas y de otros recursos gráficos que resaltan los detalles del texto.', '4.1.3. Predicción sobre el tema de la lectura a partir de signos, símbolos o ilustraciones.', '4.2.1. Reconocimiento instantáneo de palabras seleccionadas.', '4.2.2. Lectura de palabras pronunciando claramente las sílabas que las componen.', '4.2.3. Reconocimiento visual instantáneo de diptongos y triptongos en el caso del español.', '4.2.4. Selección visual instantánea de palabras con principios y finales comunes (familias de palabras).', '4.2.5. Reconocimiento visual instantáneo de palabras compuestas.', '4.2.6. Diferenciación entre palabras que se confunden fácilmente por su forma.', '4.2.7. Lectura oral de oraciones y párrafos con las palabras que reconocen instantáneamente.', '4.3.1. Diferenciación entre la lectura oral y la silenciosa.', '4.3.2. Utilización de estrategias de decodificación adecuados al texto objeto de la lectura.', '4.3.3. Aumento en su velocidad de comprensión lectora.', '4.4.1. Asociación de palabras en un texto determinado con su sinónimo correspondiente.', '4.4.2. Selección de una palabra determinada situándola en el contexto apropiado.', '4.4.3. Uso del contexto en el desarrollo de conceptos.', '4.4.4. Reconocimiento de una palabra determinada dándole una definición propia.', '4.4.5. Identificación de una palabra determinada indicando la función que desempeña en el texto.', '4.4.6. Asociación de objetos del entorno con la o las palabras que los nombran.', '4.5.1. Clasificación de objetos o de los hechos en un texto determinado según sus similitudes y diferencias.', '4.5.2. Identificación de los detalles o elementos importantes en un texto.', '4.5.3. Determinación del orden de los eventos en las historias o material informativo que lee.', '4.5.4. Formulación de respuestas a preguntas literales sobre los textos que lee.', '4.5.5. Identificación de la causa y el efecto en eventos determinados contenidos en materiales narrativos.', '4.5.6. Identificación de la idea principal y de las ideas secundarias en los textos leídos.', '4.5.7. Seguimiento de instrucciones escritas de no más de cuatro hechos o eventos.', '4.6.1. Identificación del problema y anticipación de su solución en los textos que lee.', '4.6.2. Expresión de comentarios de gusto o disgusto sobre los textos que escucha o lee.', '4.6.3. Elaboración de conclusiones tomando en cuenta los acontecimientos principales en la historia.', '4.7.1. Diferenciación entre cuento y noticia.', '4.7.2. Diferenciación entre texto informativo y texto narrativo.', '4.7.3. Búsqueda de información específica en diversos medios impresos.', '4.7.4. Definición de la estructura de los cuentos, las cartas, los instructivos y las listas.', '4.7.5. Toma de conciencia de su propio proceso de lectura tanto en voz alta como silenciosa (Control metacognitivo).', '4.7.6. Lectura voluntaria de textos literarios: rimas, retahílas, poemas y cuentos como recreación.', '4.7.7. Utilización voluntaria de la biblioteca del aula o de la escuela o de textos en formatos electrónicos para seleccionar lecturas.', '4.7.8. Lectura de listas de objetos con diferentes intenciones: compras, inventarios, almacenamiento.']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '5. Se expresa por escrito de acuerdo con los cambios que sufren las palabras al relacionarse unas con otras. 5.1. Aplica los principios de la caligrafía al expresarse por escrito. 5.2. Utiliza principios de gramática al expresarse por escrito.', ARRAY['5.1.1. Aplicación de los principios de la caligrafía: posición del cuerpo, empuñadura del lápiz, posición del papel.', '5.1.2. Direccionalidad al escribir.', '5.1.3. Linealidad al escribir (dirección izquierda-derecha).', '5.1.4. Espacios entre letras y palabras, márgenes.', '5.1.5. Introducción al uso de la letra cursiva al expresarse por escrito.', '5.1.6. Utilización, indistinta, de la letra de molde (script) y de la cursiva.', '5.2.1. Clasificación de palabras que nombran (sustantivos).', '5.2.2. Clasificación de palabras que describen (adjetivos).', '5.2.3. Utilización del pronombre como sustituto del nombre.', '5.2.4. Identificación de palabras que indican acción, sensación, estado y emoción en tiempo presente y pasado.', '5.2.5. Identificación de las partes de la oración: Sujeto y Predicado.', '5.2.6. Uso del punto al final de las oraciones y de los párrafos que escribe.', '5.2.7. Utilización de la coma para separar frases en una oración.', '5.2.8. Identificación de oraciones declarativas.', '5.2.9. Identificación de oraciones interrogativas.', '5.2.10. Utilización de los signos de interrogación en oraciones interrogativas.', '5.2.11. Identificación de oraciones exclamativas.', '5.2.12. Identificación de signos de admiración en oraciones exclamativas.', '5.2.13. Creación de oraciones declarativas, interrogativas, exclamativas.', '5.2.14. Formulación de oraciones y párrafos que reflejen concordancia de género y de número según la lengua materna.', '5.2.15. Utilización del guión mayor al escribir conversaciones.', '5.2.16. Diferenciación entre letras mayúsculas y minúsculas.', '5.2.17. Uso de la letra mayúscula al iniciar la oración, el párrafo y al escribir nombres propios.']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '6. Utiliza, con propiedad, un vocabulario abundante en su comunicación oral y escrita. 6.1. Utiliza el análisis de la estructura de las palabras para ampliar su vocabulario. 6.2. Utiliza el análisis fonético para reconocer palabras nuevas. 6.3. Utiliza el contexto para identificar los significados de palabras nuevas. 6.4. Utiliza, eficientemente, el vocabulario adquirido en la interacción con los demás.', ARRAY['6.1.1. Identificación oral de las sílabas que conforman palabras específicas.', '6.1.2. Separación oral de palabras en sílabas.', '6.1.3. Unión de sílabas para formar palabras nuevas.', '6.1.4. Identificación del número de sílabas que conforman una palabra.', '6.1.5. Sustitución del final de palabras conocidas por otras letras o combinaciones de letras para formar nuevas palabras.', '6.1.6. Lectura de palabras nuevas que se forman al sustituir las letras iniciales en palabras conocidas.', '6.1.7. Creación de palabras nuevas utilizando sílabas de palabras conocidas.', '6.1.8. Formación del plural de las palabras según el idioma.', '6.1.9. Formación de familias de palabras agregando a la raíz el afijo que forma el diminutivo y el aumentativo.', '6.1.10. Clasificación de las palabras por el número de sílabas.', '6.1.11. Clasificación de las palabras por la sílaba acentuada: agudas, graves, esdrújulas.', '6.2.1. Análisis oral (deletreo) de palabras cuyo significado desconoce.', '6.2.2. Identificación de dígrafos en palabras del vocabulario básico (ll, rr, ch, qu).', '6.2.3. Identificación de palabras que empiezan con una combinación de consonantes según el idioma que se maneje.', '6.2.4. Identificación de palabras que terminan con la misma combinación de sonidos.', '6.2.5. Identificación de sustantivos dentro de los textos y su significado por el contexto.', '6.3.1. Identificación del significado de adjetivos y verbos por las palabras anteriores y posteriores.', '6.4.1. Utilización de palabras nuevas en su conversación con los demás o en las narraciones y descripciones emitidas.', '6.4.2. Descripción de estados de ánimo utilizando las palabras apropiadas y la entonación precisa.', '6.4.3. Incorporación, al vocabulario básico, de palabras que escucha en su interacción con otros y que considera apropiadas a la situación.', '6.4.4. Introducción de palabras nuevas en los textos que escribe.', '6.4.5. Utilización del vocabulario adecuado al tipo de texto que escribe.']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '7. Redacta textos informativos y literarios apegándose a las normas del idioma. 7.1. Caracteriza los elementos presentes en textos informativos. 7.2. Caracteriza los elementos presentes en textos literarios.', ARRAY['7.1.1. Identificación de las ilustraciones como apoyo a la expresión de ideas con respecto a personas, objetos, animales y plantas.', '7.1.2. Determinación de la relación entre el título y el contenido del tema bajo estudio.', '7.1.3. Atención a las características del párrafo al redactar textos informativos.', '7.1.4. Distribución de la información en diferentes párrafos atendiendo al tema.', '7.1.5. Redacción de notas, mensajes, textos informativos y descriptivos según las normas del idioma.', '7.1.6. Utilización de los pasos a seguir en la redacción de textos.', '7.2.1. Reconocimiento de la estructura de los poemas.', '7.2.2. Identificación de la sílaba que se pronuncia con mayor fuerza en la última palabra de cada verso.', '7.2.3. Reconocimiento del sonido final en cada verso de un poema dado.', '7.2.4. Selección de las palabras que riman en un poema dado.', '7.2.5. Características del texto literario (recrea la realidad desde un punto de vista personal y refleja la subjetividad del autor).']),

('Segundo Grado', 'Comunicación y Lenguaje L 1', '8. Utiliza el lenguaje oral y escrito para adquirir información con respecto a los elementos de la vida cotidiana. 8.1. Utiliza diferentes estrategias del lenguaje oral para adquirir información en eventos de la vida cotidiana. 8.2. Utiliza diferentes estrategias para organizar la información obtenida en publicaciones periódicas, libros, bibliotecas, entre otros.', ARRAY['8.1.1. Formulación de preguntas para definir la información que recibe.', '8.1.2. Interpretación y reproducción oral de lo escuchado por medios de comunicación auditiva.', '8.1.3. Organización de la información que transmiten los medios audiovisuales.', '8.1.4. Organización de entrevistas para obtener información con respecto a eventos de la vida cotidiana.', '8.2.1. Revisión de textos que se producen para corregirlos y asegurar que puedan ser comprendidos por otras personas.', '8.2.2. Elaboración de esquemas que indican la distribución de tareas de aprendizaje.', '8.2.3. Selección de los recursos existentes y de la información pertinente para estructurar diversos documentos.']);
